# Megatron-LM rank assignment (simplified)
# Given: tp_size=4, pp_size=2, dp_size=2 (total 16 GPUs)

def build_parallel_groups(tp_size, pp_size, dp_size):
    world_size = tp_size * pp_size * dp_size
    tp_groups, pp_groups, dp_groups = [], [], []

    for pp_rank in range(pp_size):
        for dp_rank in range(dp_size):
            ranks = [pp_rank * dp_size * tp_size + dp_rank * tp_size + tp_rank
                     for tp_rank in range(tp_size)]
            tp_groups.append(ranks)

    for tp_rank in range(tp_size):
        for dp_rank in range(dp_size):
            ranks = [pp_rank * dp_size * tp_size + dp_rank * tp_size + tp_rank
                     for pp_rank in range(pp_size)]
            pp_groups.append(ranks)

    for tp_rank in range(tp_size):
        for pp_rank in range(pp_size):
            ranks = [pp_rank * dp_size * tp_size + dp_rank * tp_size + tp_rank
                     for dp_rank in range(dp_size)]
            dp_groups.append(ranks)

    return tp_groups, pp_groups, dp_groups
